import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do you calculate an interest rate?", a: "For a lump sum, interest rate can be calculated with Rate = (Future Value / Present Value)^(1 / Years) - 1. This calculator also lets you use a known rate to calculate future value." },
  { q: "What is APR vs interest rate?", a: "The interest rate is the cost of borrowing before fees. APR includes interest plus qualifying loan fees, so it better represents the annual cost of credit." },
  { q: "What is a good interest rate for a loan?", a: "A good rate depends on loan type, credit score, term, down payment, and market conditions. Lower-risk borrowers usually qualify for lower rates." },
  { q: "How does credit score affect interest rate?", a: "A higher credit score usually lowers lender risk, which can qualify you for lower interest rates and lower total interest costs." },
  { q: "What is the federal funds rate?", a: "The federal funds rate is the overnight rate banks charge each other. It influences borrowing rates across mortgages, credit cards, savings accounts, and loans." },
];

const money = (value: number, digits = 0) => formatCurrencyValue(value, { maximumFractionDigits: digits });
const futureValue = (pv: number, rate: number, years: number) => pv * Math.pow(1 + rate / 100, years);
const impliedRate = (pv: number, fv: number, years: number) => pv > 0 && years > 0 ? (Math.pow(fv / pv, 1 / years) - 1) * 100 : 0;

export default function InterestRateCalculator() {
  useCurrencyVersion();
  const [mode, setMode] = useState<"rate" | "future">("rate");
  const [presentValue, setPresentValue] = useState(10000);
  const [future, setFuture] = useState(19672);
  const [years, setYears] = useState(10);
  const [rate, setRate] = useState(7);
  const calculatedRate = impliedRate(presentValue, future, years);
  const calculatedFuture = futureValue(presentValue, rate, years);
  const displayValue = mode === "rate" ? `${calculatedRate.toFixed(2)}%` : money(calculatedFuture);
  const rows = [1, 3, 5, 7, 10, 15].map((r) => {
    const fv = futureValue(10000, r, 10);
    return { r, fv, interest: fv - 10000, monthly: Math.pow(1 + r / 100, 1 / 12) - 1 };
  });
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
  return (
    <>
      <SEOHead title="Free Interest Rate Calculator Online - Calculate Interest Rate From Any Loan or Investment | CalcHive" description="Free online interest rate calculator. Calculate the interest rate from present value, future value and time period for any loan or investment instantly. 100% free, no signup required." canonical="/interest-rate-calculator" keywords="free interest rate calculator, calculate interest rate free online, APR calculator free, find interest rate from payment free, loan interest rate calculator free" category="Financial Calculators" breadcrumbName="Free Interest Rate Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Interest Rate Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate an unknown interest rate from present value, future value, and time, or calculate future value from a known rate.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Mode</label><select value={mode} onChange={(e) => setMode(e.target.value as "rate" | "future")} className={inputClass}><option value="rate">Find interest rate</option><option value="future">Calculate future value</option></select></div><div><label className="text-sm font-semibold text-foreground block mb-2">Present value</label><input type="number" value={presentValue} onChange={(e) => setPresentValue(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Time period (years)</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div>{mode === "rate" ? <div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Future value</label><input type="number" value={future} onChange={(e) => setFuture(Number(e.target.value))} className={inputClass} /></div> : <div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" step="0.1" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div>}</div><motion.div key={`${mode}-${presentValue}-${future}-${years}-${rate}`} initial={{ opacity: .7, y: 4 }} animate={{ opacity: 1, y: 0 }}><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{mode === "rate" ? "Interest Rate" : "Future Value"}</p><p className="text-5xl sm:text-6xl font-black text-white" data-testid="result-interest-rate">{displayValue}</p></div></motion.div></section><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Interest Rate From Any Loan or Investment for Free</h2><p className="text-muted-foreground leading-relaxed">Use the relationship between present value, future value, and time to solve for the annual growth or interest rate.</p><h2 className="text-2xl font-bold text-foreground">How to Find the Rate That Matches Your Financial Goal</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Interest Rate Impact on $10,000 Over 10 Years</caption><thead className="bg-muted/60"><tr>{["Interest Rate", "Final Value", "Total Interest", "Monthly Equivalent"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((row) => <tr key={row.r}><td className="py-2.5 px-3 font-semibold">{row.r}%</td><td className="py-2.5 px-3">{money(row.fv)}</td><td className="py-2.5 px-3">{money(row.interest)}</td><td className="py-2.5 px-3">{(row.monthly * 100).toFixed(3)}%</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free APR and Interest Rate Tool for Everyone</h2><p className="text-muted-foreground leading-relaxed">Compare rates to understand how small rate differences change long-term loan or investment outcomes.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/interest-rate-calculator" headingLevel="h3" /></main>
    </>
  );
}


